#[derive(Deserialize)]
struct Cursor {
    after: Option<i64>,
    limit: Option<i64>,
}

async fn list_users(
    Query(cursor): Query<Cursor>,
    State(db): State<PgPool>,
) -> Result<Json<PagedResponse<User>>, AppError> {
    let limit = cursor.limit.unwrap_or(20).min(100);
    let after = cursor.after.unwrap_or(0);
    let users = sqlx::query_as!(User,
        "SELECT * FROM users WHERE id > $1 ORDER BY id LIMIT $2",
        after, limit + 1)
        .fetch_all(&db).await?;
    let has_more = users.len() > limit as usize;
    let items: Vec<User> = users.into_iter().take(limit as usize).collect();
    let next_cursor = items.last().map(|u| u.id);
    Ok(Json(PagedResponse { items, next_cursor, has_more }))
}

